// Time Series Forecasting using Exponential Smoothing and Trend Analysis
// This code forecasts revenue, expenses, and payroll using exponential smoothing

const items = $input.all();

// Helper function for exponential smoothing
function exponentialSmoothing(data, alpha = 0.3) {
  if (!data || data.length === 0) return [];

  const smoothed = [data[0]];
  for (let i = 1; i < data.length; i++) {
    smoothed[i] = alpha * data[i] + (1 - alpha) * smoothed[i - 1];
  }
  return smoothed;
}

// Helper function to calculate trend
function calculateTrend(data) {
  if (!data || data.length < 2) return 0;

  const n = data.length;
  let sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0;

  for (let i = 0; i < n; i++) {
    sumX += i;
    sumY += data[i];
    sumXY += i * data[i];
    sumX2 += i * i;
  }

  const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
  return slope;
}

// Helper function to forecast next period
function forecast(data, periods = 1, alpha = 0.3, beta = 0.3) {
  if (!data || data.length === 0) return [];

  const smoothed = exponentialSmoothing(data, alpha);
  const trend = calculateTrend(smoothed);

  const lastValue = smoothed[smoothed.length - 1];
  const forecasts = [];

  for (let i = 1; i <= periods; i++) {
    forecasts.push(lastValue + trend * i);
  }

  return forecasts;
}

// Extract financial data from combined inputs
const revenueData = [];
const expenseData = [];
const payrollData = [];

for (const item of items) {
  if (item.json.revenue !== undefined) {
    revenueData.push(parseFloat(item.json.revenue) || 0);
  }
  if (item.json.expenses !== undefined) {
    expenseData.push(parseFloat(item.json.expenses) || 0);
  }
  if (item.json.payroll !== undefined) {
    payrollData.push(parseFloat(item.json.payroll) || 0);
  }
}

// Forecast parameters
const forecastPeriods = 3; // Forecast next 3 periods
const alpha = 0.3; // Smoothing factor for level
const beta = 0.3; // Smoothing factor for trend

// Generate forecasts
const revenueForecast = forecast(revenueData, forecastPeriods, alpha, beta);
const expenseForecast = forecast(expenseData, forecastPeriods, alpha, beta);
const payrollForecast = forecast(payrollData, forecastPeriods, alpha, beta);

// Calculate metrics
const revenueAvg = revenueData.reduce((a, b) => a + b, 0) / revenueData.length || 0;
const expenseAvg = expenseData.reduce((a, b) => a + b, 0) / expenseData.length || 0;
const payrollAvg = payrollData.reduce((a, b) => a + b, 0) / payrollData.length || 0;

const revenueTrend = calculateTrend(revenueData);
const expenseTrend = calculateTrend(expenseData);
const payrollTrend = calculateTrend(payrollData);

// Prepare output
const output = {
  forecasts: {
    revenue: revenueForecast,
    expenses: expenseForecast,
    payroll: payrollForecast
  },
  historical: {
    revenue: revenueData,
    expenses: expenseData,
    payroll: payrollData
  },
  metrics: {
    revenue: {
      average: revenueAvg,
      trend: revenueTrend,
      nextPeriod: revenueForecast[0] || 0
    },
    expenses: {
      average: expenseAvg,
      trend: expenseTrend,
      nextPeriod: expenseForecast[0] || 0
    },
    payroll: {
      average: payrollAvg,
      trend: payrollTrend,
      nextPeriod: payrollForecast[0] || 0
    }
  },
  summary: {
    forecastPeriods: forecastPeriods,
    projectedNetIncome: (revenueForecast[0] || 0) - (expenseForecast[0] || 0) - (payrollForecast[0] || 0),
    timestamp: new Date().toISOString()
  }
};

return [{ json: output }];

// Scenario Simulation: Best Case, Likely Case, and Worst Case
// Generates three financial scenarios based on forecast data

const items = $input.all();
const forecastData = items[0].json;

// Extract baseline forecasts
const baseRevenue = forecastData.metrics?.revenue?.nextPeriod || 0;
const baseExpenses = forecastData.metrics?.expenses?.nextPeriod || 0;
const basePayroll = forecastData.metrics?.payroll?.nextPeriod || 0;

// Best Case Scenario: +15% revenue, -5% expenses
const bestCase = {
  scenario: "Best Case",
  revenue: baseRevenue * 1.15,
  expenses: baseExpenses * 0.95,
  payroll: basePayroll,
  netIncome: (baseRevenue * 1.15) - (baseExpenses * 0.95) - basePayroll,
  assumptions: {
    revenueChange: "+15%",
    expenseChange: "-5%",
    payrollChange: "0%"
  }
};

// Likely Case Scenario: Baseline forecast
const likelyCase = {
  scenario: "Likely Case",
  revenue: baseRevenue,
  expenses: baseExpenses,
  payroll: basePayroll,
  netIncome: baseRevenue - baseExpenses - basePayroll,
  assumptions: {
    revenueChange: "0%",
    expenseChange: "0%",
    payrollChange: "0%"
  }
};

// Worst Case Scenario: -10% revenue, +10% expenses
const worstCase = {
  scenario: "Worst Case",
  revenue: baseRevenue * 0.90,
  expenses: baseExpenses * 1.10,
  payroll: basePayroll,
  netIncome: (baseRevenue * 0.90) - (baseExpenses * 1.10) - basePayroll,
  assumptions: {
    revenueChange: "-10%",
    expenseChange: "+10%",
    payrollChange: "0%"
  }
};

// Calculate scenario comparison metrics
const scenarioComparison = {
  netIncomeRange: {
    best: bestCase.netIncome,
    likely: likelyCase.netIncome,
    worst: worstCase.netIncome,
    spread: bestCase.netIncome - worstCase.netIncome
  },
  revenueRange: {
    best: bestCase.revenue,
    likely: likelyCase.revenue,
    worst: worstCase.revenue,
    spread: bestCase.revenue - worstCase.revenue
  },
  expenseRange: {
    best: bestCase.expenses,
    likely: likelyCase.expenses,
    worst: worstCase.expenses,
    spread: worstCase.expenses - bestCase.expenses
  }
};

// Prepare output
const output = {
  scenarios: {
    bestCase,
    likelyCase,
    worstCase
  },
  comparison: scenarioComparison,
  baselineForecasts: {
    revenue: baseRevenue,
    expenses: baseExpenses,
    payroll: basePayroll
  },
  originalForecastData: forecastData,
  timestamp: new Date().toISOString()
};

return [{ json: output }];

// Anomaly Detection using Statistical Methods
// Detects values beyond 2 standard deviations, sudden trend changes, and unusual cash flow patterns

const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { anomalies: [], message: 'No data to analyze' } }];
}

const forecastData = items[0].json;

// Helper function to calculate mean
function calculateMean(data) {
  if (!data || data.length === 0) return 0;
  return data.reduce((sum, val) => sum + val, 0) / data.length;
}

// Helper function to calculate standard deviation
function calculateStdDev(data, mean) {
  if (!data || data.length === 0) return 0;
  const variance = data.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / data.length;
  return Math.sqrt(variance);
}

// Helper function to detect outliers (beyond 2 standard deviations)
function detectOutliers(data, threshold = 2) {
  if (!data || data.length === 0) return [];

  const mean = calculateMean(data);
  const stdDev = calculateStdDev(data, mean);
  const outliers = [];

  data.forEach((value, index) => {
    const zScore = Math.abs((value - mean) / stdDev);
    if (zScore > threshold) {
      outliers.push({
        index: index,
        value: value,
        mean: mean,
        stdDev: stdDev,
        zScore: zScore,
        deviation: value - mean
      });
    }
  });

  return outliers;
}

// Helper function to detect sudden trend changes
function detectTrendChanges(data, threshold = 0.2) {
  if (!data || data.length < 3) return [];

  const changes = [];

  for (let i = 1; i < data.length - 1; i++) {
    const prevChange = data[i] - data[i - 1];
    const nextChange = data[i + 1] - data[i];

    // Detect reversal or significant acceleration
    if (prevChange !== 0) {
      const changeRatio = Math.abs((nextChange - prevChange) / prevChange);

      if (changeRatio > threshold || (prevChange > 0 && nextChange < 0) || (prevChange < 0 && nextChange > 0)) {
        changes.push({
          index: i,
          value: data[i],
          previousChange: prevChange,
          nextChange: nextChange,
          changeRatio: changeRatio,
          type: (prevChange > 0 && nextChange < 0) ? 'reversal_down' : 
                (prevChange < 0 && nextChange > 0) ? 'reversal_up' : 'acceleration'
        });
      }
    }
  }

  return changes;
}

// Helper function to detect unusual cash flow patterns
function detectCashFlowAnomalies(revenue, expenses, payroll) {
  const anomalies = [];

  for (let i = 0; i < Math.min(revenue.length, expenses.length, payroll.length); i++) {
    const netCashFlow = revenue[i] - expenses[i] - payroll[i];
    const expenseRatio = expenses[i] / revenue[i];
    const payrollRatio = payroll[i] / revenue[i];

    // Detect negative cash flow
    if (netCashFlow < 0) {
      anomalies.push({
        index: i,
        type: 'negative_cash_flow',
        netCashFlow: netCashFlow,
        severity: 'high'
      });
    }

    // Detect unusually high expense ratio (>80%)
    if (expenseRatio > 0.8) {
      anomalies.push({
        index: i,
        type: 'high_expense_ratio',
        ratio: expenseRatio,
        severity: 'medium'
      });
    }

    // Detect unusually high payroll ratio (>50%)
    if (payrollRatio > 0.5) {
      anomalies.push({
        index: i,
        type: 'high_payroll_ratio',
        ratio: payrollRatio,
        severity: 'medium'
      });
    }
  }

  return anomalies;
}

// Extract historical data
const revenueData = forecastData.historical?.revenue || [];
const expenseData = forecastData.historical?.expenses || [];
const payrollData = forecastData.historical?.payroll || [];

// Detect anomalies
const revenueOutliers = detectOutliers(revenueData);
const expenseOutliers = detectOutliers(expenseData);
const payrollOutliers = detectOutliers(payrollData);

const revenueTrendChanges = detectTrendChanges(revenueData);
const expenseTrendChanges = detectTrendChanges(expenseData);
const payrollTrendChanges = detectTrendChanges(payrollData);

const cashFlowAnomalies = detectCashFlowAnomalies(revenueData, expenseData, payrollData);

// Compile results
const anomalies = {
  outliers: {
    revenue: revenueOutliers,
    expenses: expenseOutliers,
    payroll: payrollOutliers
  },
  trendChanges: {
    revenue: revenueTrendChanges,
    expenses: expenseTrendChanges,
    payroll: payrollTrendChanges
  },
  cashFlow: cashFlowAnomalies,
  summary: {
    totalOutliers: revenueOutliers.length + expenseOutliers.length + payrollOutliers.length,
    totalTrendChanges: revenueTrendChanges.length + expenseTrendChanges.length + payrollTrendChanges.length,
    totalCashFlowAnomalies: cashFlowAnomalies.length,
    hasAnomalies: (revenueOutliers.length + expenseOutliers.length + payrollOutliers.length + 
                   revenueTrendChanges.length + expenseTrendChanges.length + payrollTrendChanges.length + 
                   cashFlowAnomalies.length) > 0
  },
  timestamp: new Date().toISOString()
};

// Merge with original forecast data
const output = {
  ...forecastData,
  anomalies: anomalies
};

return [{ json: output }];
